    while (T--) {
        int N;
        scanf("%d", &N);
        int minTime = 0;
        char prevTime[9] = "00:00:00";
        for (int i = 0; i < N; i++) {
            char currentTime[9];
            scanf("%s", currentTime);
            int hours = 0, minutes = 0, seconds = 0;
            if (currentTime[0] != '?') hours = hours * 10 + (currentTime[0] - '0');
            if (currentTime[1] != '?') hours = hours * 10 + (currentTime[1] - '0');
            if (currentTime[3] != '?') minutes = minutes * 10 + (currentTime[3] - '0');
            if (currentTime[4] != '?') minutes = minutes * 10 + (currentTime[4] - '0');
            if (currentTime[6] != '?') seconds = seconds * 10 + (currentTime[6] - '0');
            if (currentTime[7] != '?') seconds = seconds * 10 + (currentTime[7] - '0');
            int currentTimeInSeconds = hours * 3600 + minutes * 60 + seconds;
            int prevTimeInSeconds = 0;
            if (prevTime[0] != '?') prevTimeInSeconds = prevTimeInSeconds * 10 + (prevTime[0] - '0');
            if (prevTime[1] != '?') prevTimeInSeconds = prevTimeInSeconds * 10 + (prevTime[1] - '0');
            prevTimeInSeconds *= 3600;
            if (prevTime[3] != '?') prevTimeInSeconds = prevTimeInSeconds + (prevTime[3] - '0') * 600;
            if (prevTime[4] != '?') prevTimeInSeconds = prevTimeInSeconds + (prevTime[4] - '0') * 60;
            if (prevTime[6] != '?') prevTimeInSeconds = prevTimeInSeconds + (prevTime[6] - '0') * 10;
            if (prevTime[7] != '?') prevTimeInSeconds = prevTimeInSeconds + (prevTime[7] - '0');
            if (currentTimeInSeconds < prevTimeInSeconds) {
                // Handle the case where the current time is less than the previous time
                // This could involve adjusting the current time or the previous time
            }
            minTime = max(minTime, currentTimeInSeconds - prevTimeInSeconds);
            strcpy(prevTime, currentTime);
        }
        printf("%d\n", minTime);
    }
    return 0;
}

